/*
 * Read a line from serial into buffer with strict bounds checking.
 * Returns true if a complete line was read, false on error/EOF.
 */
static bool serial_read_line(char *buf, size_t buf_size)
{
    size_t pos = 0;

    if (buf == NULL || buf_size < 2) {
        return false;
    }

    while (1) {
        int c = serial_read_char();

        if (c == EOF) {
            buf[pos] = '\0';
            return false;
        }

        /* Handle line endings */
        if (c == '\n' || c == '\r') {
            buf[pos] = '\0';
            if (pos > 0) {
                return true;
            }
            /* Skip empty lines */
            continue;
        }

        /* Ignore non-printable characters (control chars, etc.) */
        if (c < 0x20 || c > 0x7E) {
            continue;
        }

        /* Check buffer space (reserve 1 byte for null terminator) */
        if (pos >= buf_size - 1) {
            serial_write_string("ERROR: Input too long, discarding line\n");
            /* Drain remaining characters until newline */
            while (1) {
                c = serial_read_char();
                if (c == EOF || c == '\n' || c == '\r')
                    break;
            }
            buf[0] = '\0';
            pos = 0;
            continue;
        }

        buf[pos++] = (char)c;
    }
}

